def unique(l: list):
    """Return sorted unique elements in a list
    >>> unique([5, 3, 5, 2, 3, 3, 9, 0, 123])
    [0, 2, 3, 5, 9, 123]
    """
    result = []
    for elem in l:
        if elem not in result:
            result.append(elem)
    result.sort()
    return result

