    Examples
    solve("1234") = "4321"
    solve("ab") = "AB"
    solve("#a@C") = "#A@c"
    """
    result = []
    is_lower = False
    for c in s:
        if c.islower():
            is_lower = not is_lower
            result.append(c)
        elif c.isupper():
            is_lower = not is_lower
            result.append(c)
        else:
            result.append(c)
    result.reverse()
    result = "".join(result)
    if is_lower:
        result = result.lower()
    return result
